refsection.programlisting:
      
b=3;
s=3;
for k=1:10
    a=number_tobary(k,b,"bigendian");
    r=size(a,"*");
    bpow=b.^(1:r)';
    for i=1:s
        C=faurematrix ( r , i-1 );
        y=modulo(C*a,b);
        x(k,i)=sum(y./bpow);
    end
end
disp(x)

      
s=3;
b=3;
scf();
lds = lowdisc_new("faure");
lds = lowdisc_configure(lds,"-dimension",s);
lds = lowdisc_startup (lds);
k=1;
imax=3;
for i=1:imax
    npoints=(b-1)*b^(i-1);
    [lds,u]=lowdisc_next(lds,npoints);
    for j=1:s
        subplot(s,1,j)
        plot(u(:,j)',i,"bo")
        xstring(u(:,j)',i,string(k:k+npoints-1))
    end
    k=k+npoints;
end
lds = lowdisc_destroy (lds);
for j=1:s
    subplot(s,1,j)
    a = gca();
    a.data_bounds=[
    0 0
    1 imax+1
    ];
    xtitle("Faure Sequence","X"+string(j),"Block Index")
end

      
b=3;
s=3;
u=lowdisc_ldgen(3^3,3,"faure");
u=[zeros(1,s);u];
scf();
npoints=b^3;
for i=0:b-1
    for j=1:s
        subplot(s,1,j)
        indices=i*b^2+1:(i+1)*b^2
        plot(u(indices,j)',i,"bo")
        xstring(u(indices,j)',i,string(indices))
    end
end
for j=1:s
    subplot(s,1,j)
    a = gca();
    a.data_bounds=[
    0 -1
    1 b
    ];
    xtitle("Faure Sequence","X"+string(j),"Block Index")
end
